import { p as prisma } from "../../../../../../chunks/prisma.js";
import { fail, redirect, error } from "@sveltejs/kit";
import { d as deleteFile, u as uploadImage } from "../../../../../../chunks/storage.js";
const load = async ({ params }) => {
  const project = await prisma.project.findUnique({
    where: { id: params.id }
  });
  if (!project) {
    throw error(404, "Project not found");
  }
  return {
    project
  };
};
const actions = {
  update: async ({ params, request }) => {
    const formData = await request.formData();
    const title = formData.get("title");
    const description = formData.get("description");
    const content = formData.get("content");
    const thumbnailFile = formData.get("thumbnail");
    const githubUrl = formData.get("githubUrl");
    const demoUrl = formData.get("demoUrl");
    const env = formData.get("env");
    const status = formData.get("status");
    const techStackString = formData.get("techStack");
    if (!title || !description) {
      return fail(400, {
        message: "Title and description are required"
      });
    }
    const techStack = techStackString ? techStackString.split(",").map((item) => item.trim()).filter((item) => item !== "") : [];
    try {
      const existingProject = await prisma.project.findUnique({
        where: { id: params.id },
        select: { thumbnail: true }
      });
      let thumbnail = void 0;
      if (thumbnailFile && thumbnailFile.size > 0) {
        const buffer = Buffer.from(await thumbnailFile.arrayBuffer());
        thumbnail = await uploadImage(buffer, "projects", thumbnailFile.type);
        if (existingProject?.thumbnail) {
          await deleteFile(existingProject.thumbnail);
        }
      }
      await prisma.project.update({
        where: { id: params.id },
        data: {
          title,
          description,
          content,
          ...thumbnail && { thumbnail },
          githubUrl,
          demoUrl,
          env,
          status,
          techStack
        }
      });
    } catch (err) {
      console.error("Update project error:", err);
      return fail(500, { message: "Failed to update project" });
    }
    throw redirect(303, "/dashboard/projects");
  },
  delete: async ({ params }) => {
    try {
      const project = await prisma.project.findUnique({
        where: { id: params.id },
        select: { thumbnail: true }
      });
      if (project?.thumbnail) {
        await deleteFile(project.thumbnail);
      }
      await prisma.project.delete({
        where: { id: params.id }
      });
    } catch (err) {
      console.error("Delete project error:", err);
      return fail(500, { message: "Failed to delete project" });
    }
    throw redirect(303, "/dashboard/projects");
  }
};
export {
  actions,
  load
};
